<?php
if (PHP_SAPI!=='cli') { $token=getenv('DAILY_STUDIO_CRON_TOKEN')?:''; if(!$token || !hash_equals($token,$_GET['token']??'')){http_response_code(403);exit('Forbidden');}}
$root=dirname(__DIR__,3);$dbPath=$root.'/var/daily-studio.sqlite';if(!file_exists($dbPath))exit("Daily Studio database not initialized.\n");$db=new PDO('sqlite:'.$dbPath,null,null,[PDO::ATTR_ERRMODE=>PDO::ERRMODE_EXCEPTION]);$tomorrow=date('Y-m-d',strtotime('+1 day'));$channels=$db->query('SELECT channel_key,name FROM channels WHERE enabled=1')->fetchAll(PDO::FETCH_ASSOC);$missing=[];foreach($channels as $c){$s=$db->prepare('SELECT COUNT(*) FROM events WHERE channel_key=? AND date(scheduled_at)=?');$s->execute([$c['channel_key'],$tomorrow]);if(!(int)$s->fetchColumn())$missing[]=$c['name'];}$report=['date'=>$tomorrow,'missing_channels'=>$missing,'generated_at'=>date(DATE_ATOM)];file_put_contents($root.'/var/daily-studio-published/daily-check.json',json_encode($report,JSON_PRETTY_PRINT|JSON_UNESCAPED_SLASHES));echo count($missing)." missing channel(s) for $tomorrow.\n";
